import React, { useEffect, useState } from "react";
import { useAuth } from '../../Context/AuthContext';
const API = process.env.REACT_APP_API_URL || "http://localhost:5000/api";

const Riders = () => {
  const { token } = useAuth();
  const [list, setList] = useState([]);
  const [firstName, setFirstName] = useState("");
  const [lastName, setLastName] = useState("");
  const [phone, setPhone] = useState("");
  const [vehicleNumber, setVehicleNumber] = useState("");
  const [status, setStatus] = useState("available");
  const [editingRider, setEditingRider] = useState(null);
  const [message, setMessage] = useState("");

  const load = async () => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API}/riders`, { headers: { Authorization: `Bearer ${token}` } });
    if (!res.ok) {
      console.error('Failed to load riders', await res.text());
      setList([]);
      return;
    }
    const data = await res.json();
    setList(Array.isArray(data) ? data : []);
  };

  const add = async () => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API}/riders`, {
      method: "POST",
      headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
      body: JSON.stringify({ name })
    });
    if (!res.ok) {
      const err = await res.json().catch(()=>({message:'Error'}));
      alert(err.message || 'Failed to add rider');
    }
    setName("");
    load();
  };

  const remove = async (id) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API}/riders/${id}`, { method: "DELETE", headers: { Authorization: `Bearer ${token}` } });
    if (!res.ok) { alert('Failed to delete rider'); }
    load();
  };

  useEffect(() => { load(); }, []);

  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold mb-4">Riders</h2>

      <div className="flex gap-2 mb-4">
        <input className="border p-2 rounded" value={name} onChange={(e)=>setName(e.target.value)} placeholder="Rider name" />
        <button className="px-4 bg-red-600 text-white rounded" onClick={add}>Add</button>
      </div>

      <ul className="bg-white rounded shadow divide-y">
        {Array.isArray(list) && list.map(r => (
          <li key={r.rider_id} className="p-3 flex justify-between">
            <span>{r.name}</span>
            <button className="px-3 py-1 bg-red-600 text-white rounded" onClick={()=>remove(r.rider_id)}>Delete</button>
          </li>
        ))}
      </ul>
    </div>
  );
};

export default Riders;
